where 1 = 1




  and (fr.name like #{criteria.blurry,jdbcType=VARCHAR}
     or fr.remark like #{criteria.blurry,jdbcType=VARCHAR})




  and fr.create_time >= #{criteria.startTime,jdbcType=TIMESTAMP}




  and fr.create_time <= #{criteria.endTime,jdbcType=TIMESTAMP}




  and fr.permission = #{criteria.permission,jdbcType=VARCHAR}
